#include "RTC.h"
#include "mktime.h"
#include "cmsis_os2.h"


RTC_HandleTypeDef hrtc;
RTC_DateTypeDef sDate; 
RTC_TimeTypeDef sTime;

#define RTCCIF	0
#define RTCALF	1
#define s		0
#define mi	0
#define h		0
#define d		1
#define m		1
#define y		2020 //desde 1970
#define dw		1
#define wy		1

/**
	* @brief Funci�n que resetea la hora del RTC y establece las 00:00:00 del 01/01/2020
	* @param None
  * @retval None
  */
void resetHoraFecha0(void){
	setHora(s,mi,h);
	setFecha(d,m,y);
}
/**
	* @brief Funci�n que establece la hora del RTC con los parametros que se pasan a la funci�n
	* @param seg: Segundos que se quieren establecer en el RTC
	*	@param min: Minutos que se quieren establecer en el RTC
	*	@param hor: Hora que se quiere establecer en el RTC	
  * @retval None
  */
void setHora(uint8_t seg, uint8_t min, uint8_t hor){


	sTime.Hours = hor; // set hours 
  sTime.Minutes = min; // set minutes
	sTime.Seconds = seg; // set seconds	
  sTime.DayLightSaving = RTC_DAYLIGHTSAVING_NONE; 
  sTime.StoreOperation = RTC_STOREOPERATION_RESET; 
	if (HAL_RTC_SetTime(&hrtc, &sTime, RTC_FORMAT_BIN) != HAL_OK) 
  { 
		printf("Fallo al establecer la hora");
  } 

}
/**
	* @brief Funci�n que establece la fecha del RTC con los parametros que se pasan a la funci�n
	* @param dia: D�a que se quiere establecer en el RTC
	*	@param mes: Mes que se quiere establecer en el RTC
	*	@param anio: A�o que se quiere establecer en el RTC	
  * @retval None
  */
void setFecha(uint8_t dia, uint8_t mes, uint16_t anio ){

  sDate.Month = mes; // month 
  sDate.Date = dia; // date 
  sDate.Year = anio; // year 
	if (HAL_RTC_SetDate(&hrtc, &sDate, RTC_FORMAT_BIN) != HAL_OK) 
  { 
    printf("Fallo al establecer la fecha");
  }
}
/**
	* @brief Funci�n que obtiene el valor de los segundos del RTC
	* @param 
  * @retval Devuelve valor de los segundos del RTC
  */
uint8_t getSeg(void){
	uint8_t seg = 0;
	HAL_RTC_GetTime(&hrtc, &sTime, RTC_FORMAT_BIN);
	seg = sTime.Seconds;

	return seg;
}
/**
	* @brief Funci�n que obtiene el valor de los minutos del RTC
	* @param 
  * @retval Devuelve valor de los minutos del RTC
  */
uint8_t getMin(void){
	HAL_RTC_GetTime(&hrtc, &sTime, RTC_FORMAT_BIN);
  return sTime.Minutes;
}
/**
	* @brief Funci�n que obtiene el valor de la hora del RTC
	* @param 
  * @retval Devuelve valor de la hora del RTC
  */
uint8_t getHora(void){
	HAL_RTC_GetTime(&hrtc, &sTime, RTC_FORMAT_BIN);
  return sTime.Hours;
}
/**
	* @brief Funci�n que obtiene el d�a del RTC
	* @param 
  * @retval Devuelve el d�a del RTC
  */
uint8_t getDia(void){
	HAL_RTC_GetDate(&hrtc, &sDate, RTC_FORMAT_BIN);
  return sDate.Date;
}
/**
	* @brief Funci�n que obtiene el mes del RTC
	* @param 
  * @retval Devuelve el mes del RTC
  */
uint8_t getMes(void){
	HAL_RTC_GetDate(&hrtc, &sDate, RTC_FORMAT_BIN);
  return sDate.Month;
}
/**
	* @brief Funci�n que obtiene el a�o del RTC
	* @param 
  * @retval Devuelve el a�o del RTC
  */
uint16_t getAnio(void){
	uint16_t ye;
	HAL_RTC_GetDate(&hrtc, &sDate, RTC_FORMAT_BIN);
	ye = sDate.Year;
  return ye;
}
//devuelves segundos pasados desde 1 de enero de 1970
/**
	* @brief Funci�n que obtiene el valor de los segundos pasados desde el 1 de Enero de 1970
	* @param 
  * @retval Devuelve valor de los seundos pasados desde el 1/1/1970
  */
uint64_t getTotalSeconds(void){
	uint64_t segundos;
	segundos=unix_time_in_seconds(getSeg(), getMin(), getHora(), getDia(), getMes(), getAnio()); 
	return segundos;
}
/**
	* @brief Funci�n que inicializa el RTC con el formato 24h
	* @param None
  * @retval None
  */
void MX_RTC_Init(void)
{
  /** Initialize RTC Only
  */
  hrtc.Instance = RTC;
  hrtc.Init.HourFormat = RTC_HOURFORMAT_24;
  hrtc.Init.AsynchPrediv = 127;
  hrtc.Init.SynchPrediv = 255;
  hrtc.Init.OutPut = RTC_OUTPUT_DISABLE;
  hrtc.Init.OutPutPolarity = RTC_OUTPUT_POLARITY_HIGH;
  hrtc.Init.OutPutType = RTC_OUTPUT_TYPE_OPENDRAIN;
  if (HAL_RTC_Init(&hrtc) != HAL_OK)
  {
    printf("ERROR: RTC initialization failed!\n");
  }
  else
  {
    printf("RTC: HAL_RTC_Init successful\n");
  }

  /** Enable Calibration
  */
  if (HAL_RTCEx_SetCalibrationOutPut(&hrtc, RTC_CALIBOUTPUT_1HZ) != HAL_OK)
  {
        printf("Warning: RTC calibration output failed\n");
  }
  else
  {
    printf("RTC: Calibration output enabled\n");
  }

  // Configure initial time only on first boot: use a backup register marker so the
  // RTC is set to the design time (09:50:00) only once and then keeps running.
  // If the backup register contains the magic value, RTC was already configured.
  uint32_t bk = HAL_RTCEx_BKUPRead(&hrtc, RTC_BKP_DR0);
  if (bk != 0x32F2) {
    // First-time initialization: set time and date and write marker
    printf("RTC: First boot - initializing time to 09:50:00 01/01/2020\n");
    setHora(0, 50, 9); // Initial time 09:50:00 (seg, min, hor)
    setFecha(1, 1, 2020);
    HAL_RTCEx_BKUPWrite(&hrtc, RTC_BKP_DR0, 0x32F2);
    printf("RTC: Initial time set and backup register written\n");
  } else {
    printf("RTC: Already initialized - current time: %02d:%02d:%02d\n", getHora(), getMin(), getSeg());
  }

  /* Debug: report RTC clock source selected in BDCR (01=LSE,10=LSI,11=HSE/128) */
  uint32_t rtc_sel = (RCC->BDCR & RCC_BDCR_RTCSEL) >> RCC_BDCR_RTCSEL_Pos;
  switch (rtc_sel) {
    case 1: printf("RTC: Clock source = LSE (32.768 kHz external)\n"); break;
    case 2: printf("RTC: Clock source = LSI (32 kHz internal)\n"); break;
    case 3: printf("RTC: Clock source = HSE/128 (fast)\n"); break;
    default: printf("RTC: Clock source = NONE (RTC NOT RUNNING!)\n"); break;
  }

}

// Monitor thread: detects if RTC seconds stop advancing and attempts recovery by
// forcing the RTC to use LSI and reinitializing time.
static void RTC_Monitor_Thread(void *arg) {
    (void)arg;
    uint8_t prev = getSeg();
    int stuck_count = 0;
    for (;;) {
        osDelay(1000);
        uint8_t cur = getSeg();
        if (cur == prev) {
            stuck_count++;
        } else {
            stuck_count = 0;
        }
        prev = cur;
        if (stuck_count >= 3) {
            printf("RTC Monitor: detected RTC stuck at %02d, attempting recovery using LSI\n", cur);
            // Attempt to force RTC to use LSI and reset time
            // Enable power and backup domain access
            __HAL_RCC_PWR_CLK_ENABLE();
            HAL_PWR_EnableBkUpAccess();
            // Reset backup domain (this clears RTC registers)
            __HAL_RCC_BACKUPRESET_FORCE();
            __HAL_RCC_BACKUPRESET_RELEASE();

            // Configure LSI oscillator
            RCC_OscInitTypeDef RCC_OscInitStructLSI = {0};
            RCC_OscInitStructLSI.OscillatorType = RCC_OSCILLATORTYPE_LSI;
            RCC_OscInitStructLSI.LSIState = RCC_LSI_ON;
            RCC_OscInitStructLSI.PLL.PLLState = RCC_PLL_NONE;
            if (HAL_RCC_OscConfig(&RCC_OscInitStructLSI) == HAL_OK) {
                RCC_PeriphCLKInitTypeDef PeriphClkInitStructLSI = {0};
                PeriphClkInitStructLSI.PeriphClockSelection = RCC_PERIPHCLK_RTC;
                PeriphClkInitStructLSI.RTCClockSelection = RCC_RTCCLKSOURCE_LSI;
                if (HAL_RCCEx_PeriphCLKConfig(&PeriphClkInitStructLSI) == HAL_OK) {
                    __HAL_RCC_RTC_ENABLE();
                    // Re-initialize RTC instance
                    HAL_RTC_DeInit(&hrtc);
                    hrtc.Instance = RTC;
                    hrtc.Init.HourFormat = RTC_HOURFORMAT_24;
                    hrtc.Init.AsynchPrediv = 127;
                    hrtc.Init.SynchPrediv = 255;
                    hrtc.Init.OutPut = RTC_OUTPUT_DISABLE;
                    hrtc.Init.OutPutPolarity = RTC_OUTPUT_POLARITY_HIGH;
                    hrtc.Init.OutPutType = RTC_OUTPUT_TYPE_OPENDRAIN;
                    if (HAL_RTC_Init(&hrtc) == HAL_OK) {
                        setHora(0, 50, 9);
                        setFecha(1,1,2020);
                        HAL_RTCEx_BKUPWrite(&hrtc, RTC_BKP_DR0, 0x32F2);
                        printf("RTC Monitor: recovery done, RTC set to 09:50:00 using LSI\n");
                    } else {
                        printf("RTC Monitor: HAL_RTC_Init failed after forcing LSI\n");
                    }
                } else {
                    printf("RTC Monitor: HAL_RCCEx_PeriphCLKConfig failed for LSI\n");
                }
            } else {
                printf("RTC Monitor: HAL_RCC_OscConfig failed to start LSI\n");
            }
            // reset counter and continue monitoring
            stuck_count = 0;
        }
    }
}

void RTC_StartMonitor(void) {
    const osThreadAttr_t attr = { .name = "rtc_mon", .stack_size = 512 };
    osThreadNew(RTC_Monitor_Thread, NULL, &attr);
}

