void HAL_RTC_MspInit(RTC_HandleTypeDef* hrtc)
{
  RCC_OscInitTypeDef        RCC_OscInitStruct = {0};
  RCC_PeriphCLKInitTypeDef  PeriphClkInitStruct = {0};

  /*##-1- Enables the PWR Clock and Enables access to the backup domain */
  __HAL_RCC_PWR_CLK_ENABLE();
  HAL_PWR_EnableBkUpAccess();

  /* Try LSI first (more reliable on boards without LSE crystal) */
  printf("RTC MSP: Attempting to use LSI as RTC clock source...\n");
  RCC_OscInitStruct.OscillatorType =  RCC_OSCILLATORTYPE_LSI;
  RCC_OscInitStruct.PLL.PLLState = RCC_PLL_NONE;
  RCC_OscInitStruct.LSIState = RCC_LSI_ON;

  if (HAL_RCC_OscConfig(&RCC_OscInitStruct) == HAL_OK)
  {
    printf("RTC MSP: LSI started successfully\n");
    PeriphClkInitStruct.PeriphClockSelection = RCC_PERIPHCLK_RTC;
    PeriphClkInitStruct.RTCClockSelection = RCC_RTCCLKSOURCE_LSI;
    if (HAL_RCCEx_PeriphCLKConfig(&PeriphClkInitStruct) == HAL_OK)
    {
      __HAL_RCC_RTC_ENABLE();
      printf("RTC MSP: LSI selected as RTC clock - RTC enabled\n");
      return;
    }
    printf("RTC MSP: Failed to select LSI as RTC clock\n");
  }
  else
  {
    printf("RTC MSP: Failed to start LSI\n");
  }

  /* If LSI fails, try LSE */
  printf("RTC MSP: Attempting to use LSE as fallback...\n");
  RCC_OscInitStruct.OscillatorType =  RCC_OSCILLATORTYPE_LSE;
  RCC_OscInitStruct.PLL.PLLState = RCC_PLL_NONE;
  RCC_OscInitStruct.LSEState = RCC_LSE_ON;

  if (HAL_RCC_OscConfig(&RCC_OscInitStruct) == HAL_OK)
  {
    printf("RTC MSP: LSE started successfully\n");
    PeriphClkInitStruct.PeriphClockSelection = RCC_PERIPHCLK_RTC;
    PeriphClkInitStruct.RTCClockSelection = RCC_RTCCLKSOURCE_LSE;
    if (HAL_RCCEx_PeriphCLKConfig(&PeriphClkInitStruct) == HAL_OK)
    {
      __HAL_RCC_RTC_ENABLE();
      printf("RTC MSP: LSE selected as RTC clock - RTC enabled\n");
      return;
    }
    printf("RTC MSP: Failed to select LSE as RTC clock\n");
  }
  else
  {
    printf("RTC MSP: Failed to start LSE\n");
  }

  /* If both LSE and LSI failed, try HSE/128 as last resort */
  printf("RTC MSP: Attempting to use HSE/128 as final fallback...\n");
  RCC_OscInitStruct.OscillatorType =  RCC_OSCILLATORTYPE_HSE;
  RCC_OscInitStruct.PLL.PLLState = RCC_PLL_NONE;
  RCC_OscInitStruct.HSEState = RCC_HSE_ON;

  if (HAL_RCC_OscConfig(&RCC_OscInitStruct) == HAL_OK)
  {
    printf("RTC MSP: HSE started successfully\n");
    PeriphClkInitStruct.PeriphClockSelection = RCC_PERIPHCLK_RTC;
    PeriphClkInitStruct.RTCClockSelection = RCC_RTCCLKSOURCE_HSE_DIV128;
    if (HAL_RCCEx_PeriphCLKConfig(&PeriphClkInitStruct) == HAL_OK)
    {
      __HAL_RCC_RTC_ENABLE();
      printf("RTC MSP: HSE/128 selected as RTC clock - RTC enabled\n");
      return;
    }
    printf("RTC MSP: Failed to select HSE/128 as RTC clock\n");
  }
  else
  {
    printf("RTC MSP: Failed to start HSE\n");
  }

  printf("RTC MSP: ERROR - RTC clock source initialization failed!\n");
}

